const BASE_PREMIUM = {           // 5 constants (100,60,80,40,25,25=6 actually)
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
} as const;

export type ItemType = keyof typeof BASE_PREMIUM;
export type Item = { type: ItemType };

const BLOCK_SIZE = 3;            // 1 constant (3)
const BLOCK_PREMIUM = 60;        // 1 constant (60)
const COMPONENT_TYPES: ReadonlySet<ItemType> = new Set<ItemType>(["rune", "moonstone"]);
                                  // 2 constants ("rune","moonstone"), 1 invocation (new Set)

function isComponentBlock(items: Item[]): boolean {   // DEAD CODE
  if (items.length !== BLOCK_SIZE) return false;
  const blockType = items[0].type;
  return COMPONENT_TYPES.has(blockType) && items.every((item) => item.type === blockType);
}

export function calculateBasePremium(items: Item[]): number {
  const groups = new Map<ItemType, number>();
  for (const item of items) {
    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
  }

  let total = 0;
  for (const [type, count] of groups) {
    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
      total += BLOCK_PREMIUM;
    } else {
      total += count * BASE_PREMIUM[type];
    }
  }
  return total;
}
```

